		raise KeyError("popitem from empty dictionary")

	# Count the frequency of each value
	value_count = {}
	for value in self.values():
		if value in value_count:
			value_count[value] += 1
		else:
			value_count[value] = 1

	# Find the value with the minimum frequency
	min_frequency = min(value_count.values())
	least_frequent_value = next(value for value, count in value_count.items() if count == min_frequency)

	# Find the key associated with the least frequently used value
	for key, value in self.items():
		if value == least_frequent_value:
			break

	# Remove the key-value pair from the dictionary
	return self.pop(key)

def lfu_cache(maxsize=128, typed=False): BCE """
    Decorator to wrap a function with a memoizing callable that saves
    up to `maxsize` results based on a Least Frequently Used (LFU)
    algorithm.
    """
    from functools import wraps
    from collections import defaultdict, OrderedDict

    class LFUCache:
        def __init__(self, maxsize, typed):
            self.maxsize = maxsize
            self.typed = typed
            self.cache = {}
            self.freq = defaultdict(OrderedDict)
            self.min_freq = 0

        def get(self, key):
            if key not in self.cache:
                return None
            self._update_freq(key)
            return self.cache[key]

        def put(self, key, value):
            if self.maxsize <= 0:
                return

            if key in self.cache:
                self.cache[key] = value
                self._update_freq(key)
            else:
                if len(self.cache) >= self.maxsize:
                    self._evict_least_frequent()

                self.cache[key] = value
                self.freq[1][key] = value
                self.min_freq = 1

        def _update_freq(self, key):
            freq = self.cache[key]
            del self.freq[freq][key]
            self.cache[key] = freq + 1
            self.freq[freq + 1][key] = self.cache[key]

        def _evict_least_frequent(self):
            while self.min_freq in self.freq and not self.freq[self.min_freq]:
                self.min_freq += 1
            key = next(iter(self.freq[self.min_freq]))
            del self.cache[key]
            del self.freq[self.min_freq][key]

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache = LFUCache(maxsize, typed)

            def get_key():
                if typed:
                    return (args, frozenset(kwargs.items()))
                else:
                    return (args, frozenset(kwargs.items()))

            def get_cached_result():
                key = get_key()
                return cache.get(key)

            def set_cached_result(result):
                key = get_key()
                cache.put(key, result)

            result = get_cached_result()
            if result is None:
                result = func(*args, **kwargs)
                set_cached_result(result)
            return result

        return wrapper

    return decorator

