    Given a frequency string with a number and a unit of time, return a corresponding
    datetime.timedelta instance or None if the frequency is None or "always".

    For instance, given "3 weeks", return datetime.timedelta(weeks=3)

    Raise ValueError if the given frequency cannot be parsed.
    """
    if frequency is None or frequency.lower() == "always":
        return None

    from datetime import timedelta

    # Define supported time units
    time_units_mapping = {
        "day": "days",
        "days": "days",
        "week": "weeks",
        "weeks": "weeks",
        "month": "months",
        "months": "months",
        "year": "years",
        "years": "years"
    }

    # Split the frequency string into number and unit
    parts = frequency.split()
    if len(parts) != 2:
        raise ValueError("Frequency string must contain a number and a unit.")

    number = int(parts[0])
    unit = parts[1].lower()

    # Check if the unit is supported
    if unit not in time_units_mapping:
        raise ValueError(f"Unsupported time unit: {unit}")

    # Create the timedelta instance
    if unit in ["days", "day"]:
        return timedelta(days=number)
    elif unit in ["weeks", "week"]:
        return timedelta(weeks=number)
    elif unit in ["months", "month"]:
        return timedelta(months=number)
    elif unit in ["years", "year"]:
        return timedelta(years=number)

    # This line should never be reached due to the previous check
    raise ValueError("Unexpected error occurred.")

